<template>
  <Transition name="modal">
    <div v-if="show" class="kid-content-modal-overlay" @click="handleOverlayClick">
      <div class="kid-content-modal" :class="[`size-${size}`]" @click.stop>
        <!-- 头部 -->
        <div v-if="title || showClose" class="kid-content-modal-header">
          <h3 class="kid-content-modal-title">{{ title }}</h3>
          <button v-if="closable && showClose" class="close-btn" @click="handleClose">✕</button>
        </div>

        <!-- 内容区域 -->
        <div class="kid-content-modal-body">
          <slot />
        </div>

        <!-- 底部按钮 -->
        <div v-if="showFooter" class="kid-content-modal-footer">
          <slot name="footer">
            <button
              class="confirm-button"
              :class="[`variant-${confirmVariant}`]"
              @click="handleConfirm"
            >
              {{ confirmText }}
            </button>
          </slot>
        </div>
      </div>
    </div>
  </Transition>
</template>

<script setup lang="ts">
import { onMounted, onUnmounted } from 'vue';

interface Props {
  show: boolean;
  title?: string;
  size?: 'sm' | 'md' | 'lg' | 'xl';
  closable?: boolean;
  showClose?: boolean;
  showFooter?: boolean;
  confirmText?: string;
  confirmVariant?: 'primary' | 'secondary' | 'success' | 'danger';
  closeOnClickOverlay?: boolean;
}

const props = withDefaults(defineProps<Props>(), {
  size: 'md',
  closable: true,
  showClose: true,
  showFooter: false,
  confirmText: '确定',
  confirmVariant: 'primary',
  closeOnClickOverlay: true,
});

const emit = defineEmits<{
  'update:show': [value: boolean];
  confirm: [];
  close: [];
}>();

function handleConfirm() {
  emit('confirm');
}

function handleClose() {
  emit('update:show', false);
  emit('close');
}

function handleOverlayClick() {
  if (props.closeOnClickOverlay) {
    handleClose();
  }
}

// ESC 键关闭
function handleEscapeKey(event: KeyboardEvent) {
  if (event.key === 'Escape' || event.keyCode === 27) {
    if (props.closable && props.showClose) {
      handleClose();
    }
  }
}

onMounted(() => {
  if (props.show) {
    document.addEventListener('keydown', handleEscapeKey);
  }
});

onUnmounted(() => {
  document.removeEventListener('keydown', handleEscapeKey);
});
</script>

