<template>
  <Transition name="modal">
    <div v-if="show" class="kid-confirm-overlay" @click="handleOverlayClick">
      <div class="kid-confirm-modal" :class="[`type-${type}`]" @click.stop>
        <div class="confirm-icon">{{ icon }}</div>
        <h3 class="confirm-title">{{ title }}</h3>
        <p v-if="message" class="confirm-message">{{ message }}</p>
        <slot name="message">
          <p v-if="message" class="confirm-message">{{ message }}</p>
        </slot>
        <div class="confirm-actions">
          <KidButton
            v-if="showCancel"
            variant="secondary"
            @click="handleCancel"
          >
            {{ cancelText }}
          </KidButton>
          <KidButton
            :variant="confirmVariant"
            @click="handleConfirm"
          >
            {{ confirmText }}
          </KidButton>
        </div>
      </div>
    </div>
  </Transition>
</template>

<script setup lang="ts">
import KidButton from './KidButton.vue';
import { onMounted, onUnmounted } from 'vue';

interface Props {
  show: boolean;
  title: string;
  message: string;
  type?: 'info' | 'success' | 'warning' | 'error' | 'question';
  icon?: string;
  showCancel?: boolean;
  confirmText?: string;
  cancelText?: string;
  confirmVariant?: 'primary' | 'danger' | 'success' | 'warning';
  closeOnClickOverlay?: boolean;
}

const props = withDefaults(defineProps<Props>(), {
  type: 'question',
  icon: '',
  showCancel: true,
  confirmText: '确定',
  cancelText: '取消',
  confirmVariant: 'primary',
  closeOnClickOverlay: false,
});

const emit = defineEmits<{
  'update:show': [value: boolean];
  confirm: [];
  cancel: [];
  close: [];
}>();

// 根据类型设置默认图标
const getDefaultIcon = () => {
  if (props.icon) return props.icon;
  const icons = {
    info: 'ℹ️',
    success: '✅',
    warning: '⚠️',
    error: '❌',
    question: '🤔',
  };
  return icons[props.type];
};

function handleConfirm() {
  emit('confirm');
}

function handleCancel() {
  emit('cancel');
  emit('update:show', false);
}

function handleOverlayClick() {
  if (props.closeOnClickOverlay) {
    emit('update:show', false);
    emit('close');
  }
}

// ESC 键关闭
function handleEscapeKey(event: KeyboardEvent) {
  if (event.key === 'Escape' || event.keyCode === 27) {
    if (props.showCancel && props.closeOnClickOverlay) {
      handleCancel();
    } else if (props.closeOnClickOverlay) {
      emit('update:show', false);
      emit('close');
    }
  }
}

onMounted(() => {
  if (props.show) {
    document.addEventListener('keydown', handleEscapeKey);
  }
});

onUnmounted(() => {
  document.removeEventListener('keydown', handleEscapeKey);
});
</script>

